import React, { useState } from "react";
import { Link, useHistory } from "react-router-dom";
import { useAuth } from "../Context/AuthContext";
import logo from "../../images/logo.png";

const Sidebar = ({ isOpen = false, onToggle = () => {}, isCollapsed = false, onToggleCollapse = () => {} }) => {
  const { currentUser, logout } = useAuth();
  const history = useHistory();
  const [expandedSections, setExpandedSections] = useState({});

  const handleLogout = async () => {
    try {
      await logout();
      history.push("/");
    } catch (error) {
      console.log(error);
    }
  };

  const toggleSection = (section) => {
    setExpandedSections(prev => ({
      ...prev,
      [section]: !prev[section]
    }));
  };

  const menuItems = [
    {
      id: 'dashboard',
      icon: 'fas fa-home',
      label: 'Dashboard',
      link: '/dashboard',
      badge: null
    },
    {
      id: 'participantes',
      icon: 'fas fa-users',
      label: 'Participantes',
      link: null,
      badge: '12',
      submenu: [
        { label: 'Lista de Participantes', link: '/participantes' },
        { label: 'Nuevo Participante', link: '/participantes/nuevo' },
        { label: 'Calendario', link: '/participantes/calendario' },
        { label: 'Perfiles', link: '/participantes/perfiles' }
      ]
    },
    {
      id: 'profesionales',
      icon: 'fas fa-user-md',
      label: 'Profesionales',
      link: null,
      badge: null,
      submenu: [
        { label: 'Directorio', link: '/profesionales' },
        { label: 'Agenda', link: '/profesionales/agenda' },
        { label: 'Carga de Trabajo', link: '/profesionales/carga' }
      ]
    },
    {
      id: 'financiero',
      icon: 'fas fa-dollar-sign',
      label: 'Módulo Financiero',
      link: null,
      badge: '3',
      submenu: [
        { label: 'Mensualidades', link: '/financiero/mensualidades' },
        { label: 'Proyecciones', link: '/financiero/proyecciones' },
        { label: 'Reportes', link: '/financiero/reportes' },
        { label: 'Recordatorios', link: '/financiero/recordatorios' }
      ]
    },
    {
      id: 'formularios',
      icon: 'fas fa-clipboard-list',
      label: 'Formularios',
      link: null,
      badge: '5',
      submenu: [
        { label: 'Pendientes', link: '/formularios/pendientes' },
        { label: 'Progreso', link: '/formularios/progreso' },
        { label: 'Alertas', link: '/formularios/alertas' },
        { label: 'Exportar', link: '/formularios/exportar' }
      ]
    },
    {
      id: 'reportes',
      icon: 'fas fa-chart-bar',
      label: 'Reportes',
      link: null,
      badge: null,
      submenu: [
        { label: 'Estadísticas', link: '/reportes/estadisticas' },
        { label: 'Demográficos', link: '/reportes/demograficos' },
        { label: 'Ejecutivos', link: '/reportes/ejecutivos' },
        { label: 'Personalizados', link: '/reportes/personalizados' }
      ]
    },
    {
      id: 'configuracion',
      icon: 'fas fa-cog',
      label: 'Configuración',
      link: null,
      badge: null,
      submenu: [
        { label: 'Usuarios', link: '/configuracion/usuarios' },
        { label: 'Permisos', link: '/configuracion/permisos' },
        { label: 'Sistema', link: '/configuracion/sistema' },
        { label: 'Auditoría', link: '/configuracion/auditoria' }
      ]
    }
  ];

  return (
    <>
      {/* Backdrop para móviles */}
      {isOpen && (
        <div
          onClick={onToggle}
          className="fixed inset-0 bg-black bg-opacity-30 z-40 md:hidden"
        ></div>
      )}

      <aside
        className={`fixed left-0 top-0 h-screen ${isCollapsed ? 'w-16' : 'w-64'} bg-gradient-to-b from-primary to-secondary shadow-xl z-50 transform transition-all duration-300 ${
          isOpen ? "translate-x-0" : "-translate-x-full"
        } md:translate-x-0`}
      >
        <div className="p-6 border-b border-white border-opacity-20">
          <div className={`flex items-center ${isCollapsed ? 'justify-center' : 'space-x-3'}`}>
            <div className={`bg-white rounded-xl flex items-center justify-center shadow-lg ${isCollapsed ? 'w-10 h-10' : 'w-12 h-12'}`}>
              <img 
                src={logo} 
                alt="Logo" 
                className={`object-contain ${isCollapsed ? 'w-6 h-6' : 'w-8 h-8'}`}
              />
            </div>
            {!isCollapsed && (
              <div>
                <h2 className="text-lg font-Montserrat font-bold text-white">Todo por un Alma</h2>
                <p className="text-xs font-Poppins text-white text-opacity-80">Sistema de Gestión</p>
              </div>
            )}
            {/* Botón cerrar en móvil */}
            <button
              onClick={onToggle}
              className="ml-auto md:hidden p-2 rounded hover:bg-gray-100"
              aria-label="Cerrar menú"
            >
              <i className="fas fa-times"></i>
            </button>
            {/* Botón colapsar en desktop */}
            <button
              onClick={onToggleCollapse}
              className="hidden md:inline-flex ml-auto p-2 rounded hover:bg-gray-100"
              aria-label="Colapsar menú"
            >
              <i className={`fas ${isCollapsed ? 'fa-angle-double-right' : 'fa-angle-double-left'}`}></i>
            </button>
          </div>
        </div>

        <nav className="p-4 flex-1 overflow-y-auto">
          <ul className="space-y-1">
            {menuItems.map((item) => (
              <li key={item.id}>
                {item.link ? (
                  <Link
                    to={item.link}
                    className={`flex items-center ${isCollapsed ? 'justify-center' : 'justify-between'} px-4 py-3 text-white text-opacity-90 rounded-xl hover:bg-white hover:bg-opacity-20 hover:text-white transition-all duration-200 group`}
                  >
                    <div className="flex items-center">
                      <i className={`${item.icon} text-lg ${isCollapsed ? '' : 'mr-3'} group-hover:scale-110 transition-transform`}></i>
                      {!isCollapsed && <span className="font-Poppins font-medium">{item.label}</span>}
                    </div>
                    {!isCollapsed && item.badge && (
                      <span className="bg-red-500 text-white text-xs rounded-full px-2 py-1 font-Poppins font-medium shadow-lg">
                        {item.badge}
                      </span>
                    )}
                  </Link>
                ) : (
                  <div>
                    <button
                      onClick={() => toggleSection(item.id)}
                      className={`flex items-center ${isCollapsed ? 'justify-center' : 'justify-between'} w-full px-4 py-3 text-white text-opacity-90 rounded-xl hover:bg-white hover:bg-opacity-20 hover:text-white transition-all duration-200 group`}
                    >
                      <div className="flex items-center">
                        <i className={`${item.icon} text-lg ${isCollapsed ? '' : 'mr-3'} group-hover:scale-110 transition-transform`}></i>
                        {!isCollapsed && <span className="font-Poppins font-medium">{item.label}</span>}
                      </div>
                      {!isCollapsed && (
                        <div className="flex items-center space-x-2">
                          {item.badge && (
                          <span className="bg-red-500 text-white text-xs rounded-full px-2 py-1 font-Poppins font-medium shadow-lg">
                            {item.badge}
                          </span>
                          )}
                          <i className={`fas fa-chevron-down text-sm transition-transform duration-200 ${
                            expandedSections[item.id] ? 'rotate-180' : ''
                          }`}></i>
                        </div>
                      )}
                    </button>

                    {!isCollapsed && expandedSections[item.id] && (
                      <ul className="ml-8 mt-2 space-y-1">
                        {item.submenu.map((subItem, index) => (
                          <li key={index}>
                            <Link
                              to={subItem.link}
                              className="flex items-center px-4 py-2 text-sm text-white text-opacity-70 rounded-lg hover:bg-white hover:bg-opacity-10 hover:text-white transition-all duration-200 font-Poppins"
                            >
                              <i className="fas fa-circle text-xs mr-3 opacity-50"></i>
                              {subItem.label}
                            </Link>
                          </li>
                        ))}
                      </ul>
                    )}
                  </div>
                )}
              </li>
            ))}
          </ul>
        </nav>

        {/* Información del Usuario */}
        <div className="p-4 border-t border-white border-opacity-20 mt-auto">
          <div className={`flex items-center ${isCollapsed ? 'justify-center' : 'space-x-3'} mb-3`}>
            <div className="relative">
              {currentUser?.photoURL ? (
                <img
                  src={currentUser.photoURL}
                  alt="Usuario"
                  className={`rounded-full border-2 border-white shadow-lg ${isCollapsed ? 'w-8 h-8' : 'w-10 h-10'}`}
                />
              ) : (
                <div className={`rounded-full border-2 border-white shadow-lg bg-white flex items-center justify-center ${isCollapsed ? 'w-8 h-8' : 'w-10 h-10'}`}>
                  <i className="fas fa-user text-primary text-sm"></i>
                </div>
              )}
              <div className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-400 rounded-full border-2 border-white"></div>
            </div>
            {!isCollapsed && (
              <div className="flex-1">
                <p className="text-sm font-Poppins font-medium text-white truncate">
                  {currentUser?.displayName || currentUser?.email}
                </p>
                <p className="text-xs font-Poppins text-white text-opacity-70">Administrador</p>
              </div>
            )}
          </div>

          <button
            onClick={handleLogout}
            className={`flex items-center ${isCollapsed ? 'justify-center' : ''} w-full px-4 py-2 text-sm text-white text-opacity-90 rounded-xl hover:bg-red-500 hover:bg-opacity-20 transition-all duration-200 font-Poppins font-medium group`}
          >
            <i className="fas fa-sign-out-alt mr-3 group-hover:scale-110 transition-transform"></i>
            {!isCollapsed && 'Cerrar Sesión'}
          </button>
        </div>
      </aside>
    </>
  );
};

export default Sidebar;
